// Type declarations for direct lucide-react ESM icon imports.
// Required because Next.js barrel optimization breaks named imports like `Map`
// (which shadows the JS global). We import icons directly instead:
//   import Star from 'lucide-react/dist/esm/icons/star'
//
// Each module exports a single React component as default.

